module width_8to16(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output valid_out,
    output [15:0] data_out
);
  reg [7:0] data_lock;
  reg [1:0] valid_out_reg;
  reg [15:0] data_out_reg;
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      data_out_reg <= 16'b0;
    end else if (valid_in && flag) begin
      data_out_reg <= {data_lock, data_in};
    end
  end
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      valid_out_reg <= 2'b0;
    end else if (valid_in && flag) begin
      valid_out_reg <= 2'b1;
    end else begin
      valid_out_reg <= 2'b0;
    end
  end
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      data_lock <= 8'b0;
    end else if (valid_in && !flag) begin
      data_lock <= data_in;
    end
  end
  assign valid_out = valid_out_reg[1];
  assign data_out = data_out_reg;
endmodule
